challenges.solution:
function parseSensor(raw) {
  const [type, value] = raw.split(":");
  return { type, value: Number(value) };
}

function formatReading(sensor) {
  return `${sensor.type.toUpperCase()}: ${sensor.value}`;
}

const tempReading = parseSensor("temp:42");
const powerReading = parseSensor("power:100");

